#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    int n = online.size();
    if (n == 0) return -1;

    // Step 1: Compute topological order
    vector<vector<int>> adj(n);
    vector<int> in_degree(n, 0);
    for (auto& e : edges) {
        int u = e[0];
        int v = e[1];
        adj[u].push_back(v);
        in_degree[v]++;
    }

    queue<int> q;
    for (int i = 0; i < n; ++i) {
        if (in_degree[i] == 0) q.push(i);
    }

    vector<int> top_order;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        top_order.push_back(u);
        for (int v : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) q.push(v);
        }
    }

    // Step 2: Find max edge cost
    long long max_cost = 0;
    for (auto& e : edges) {
        max_cost = max(max_cost, e[2]);
    }

    // Step 3: Binary search
    long long low = 0, high = max_cost;
    long long ans = -1;

    while (low <= high) {
        long long mid = (low + high) / 2;
        // Check if there's a valid path with minimum edge cost >= mid
        vector<long long> dp(n, LLONG_MAX);
        dp[0] = 0;
        for (int u : top_order) {
            if (dp[u] == LLONG_MAX) continue;
            for (auto& e : edges) {
                if (e[0] != u) continue;
                int v = e[1];
                long long cost = e[2];
                if (online[u] && online[v] && cost >= mid) {
                    if (dp[u] + cost < dp[v]) {
                        dp[v] = dp[u] + cost;
                    }
                }
            }
        }
        if (dp[n-1] <= k) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}

