function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    if (n === 0) return -1;

    // Step 1: Topological sort
    const adjTopo = new Array(n).fill(0).map(() => []);
    const inDegree = new Array(n).fill(0);
    for (const e of edges) {
        const u = e[0];
        const v = e[1];
        adjTopo[u].push(v);
        inDegree[v]++;
    }

    const q: number[] = [];
    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) {
            q.push(i);
        }
    }

    const topOrder: number[] = [];
    while (q.length > 0) {
        const u = q.shift()!;
        topOrder.push(u);
        for (const v of adjTopo[u]) {
            inDegree[v]--;
            if (inDegree[v] === 0) {
                q.push(v);
            }
        }
    }

    // Step 2: Build adjacency list for check function
    const adjCheck = new Array(n).fill(0).map(() => []);
    for (const e of edges) {
        const u = e[0];
        const v = e[1];
        const cost = e[2];
        adjCheck[u].push([v, cost]);
    }

    // Step 3: Find max edge cost
    let maxEdgeCost = 0;
    for (const e of edges) {
        maxEdgeCost = Math.max(maxEdgeCost, e[2]);
    }

    // Step 4: Binary search
    let low = 0, high = maxEdgeCost;
    let ans = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const dp = new Array(n).fill(Infinity);
        dp[0] = 0;

        for (const u of topOrder) {
            if (dp[u] === Infinity) continue;
            for (const [v, cost] of adjCheck[u]) {
                if (online[u] && online[v] && cost >= mid) {
                    if (dp[u] + cost < dp[v]) {
                        dp[v] = dp[u] + cost;
                    }
                }
            }
        }

        if (dp[n - 1] <= k) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
