    while (!q.empty()) {
        int u = q.front();
        q.pop();
        top_order.push_back(u);
        for (int v : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) q.push(v);
        }
    }

    // Step 2: Find max edge cost
    long long max_cost = 0;
    for (auto& e : edges) {
        max_cost = max(max_cost, e[2]);
