function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    if (n === 0) return -1;

    // Build adjacency list with cost
    const adj: [number, number][] = [];
    for (let i = 0; i < n; i++) {
        adj.push([]);
    }
    const in_degree: number[] = new Array(n).fill(0);
    for (const e of edges) {
        const u = e[0];
        const v = e[1];
        const cost = e[2];
        adj[u].push([v, cost]);
        in_degree[v]++;
    }

    // Topological sort using Kahn's algorithm
    const top_order: number[] = [];
    const q: number[] = [];
    for (let i = 0; i < n; i++) {
        if (in_degree[i] === 0) {
            q.push(i);
        }
    }
    while (q.length > 0) {
        const u = q.shift()!;
        top_order.push(u);
        for (const [v, cost] of adj[u]) {
            in_degree[v]--;
            if (in_degree[v] === 0) {
                q.push(v);
            }
        }
    }

    // Find max edge cost
    let max_edge_cost = 0;
    for (const e of edges) {
        max_edge_cost = Math.max(max_edge_cost, e[2]);
    }

    // Binary search
    let low = 0, high = max_edge_cost;
    let ans = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        // Check if there's a valid path with min edge >= mid
        const dp: number[] = new Array(n).fill(Number.MAX_VALUE);
        dp[0] = 0;
        for (const u of top_order) {
            if (dp[u] === Number.MAX_VALUE) continue;
            for (const [v, cost] of adj[u]) {
                if (online[u] && online[v] && cost >= mid) {
                    if (dp[u] + cost < dp[v]) {
                        dp[v] = dp[u] + cost;
                    }
                }
            }
        }
        if (dp[n-1] <= k) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
