```typescript
function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    if (n === 0) return -1;

    // Step 1: Compute topological order
    const adj: number[][] = new Array(n).fill(0).map(() => []);
    const in_degree: number[] = new Array(n).fill(0);
    for (const e of edges) {
        const u = e[0];
        const v = e[1];
        adj[u].push(v);
        in_degree[v]++;
    }

    const q: number[] = [];
    for (let i = 0; i < n; i++) {
        if (in_degree[i] === 0) {
            q.push(i);
        }
    }

    const top_order: number[] = [];
    while (q.length > 0) {
        const u = q.shift()!;
        top_order.push(u);
        for (const v of adj[u]) {
            in_degree[v]--;
            if (in_degree[v] === 0) {
                q.push(v);
            }
        }
    }

    // Step 2: Find max edge cost
    let max_edge = 0;
    for (const e of edges) {
        if (e[2] > max_edge) {
            max_edge = e[2];
        }
    }

    // Step 3: Binary search
    let low = 0, high = max_edge;
    let ans = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        // Check if there's a valid path with min edge >= mid
        const dp: number[] = new Array(n).fill(Number.MAX_VALUE);
        dp[0] = 0;
        for (const u of top_order) {
            if (dp[u] === Number.MAX_VALUE) continue;
            for (const e of edges) {
                if (e[0] !== u) continue;
                const v = e[1];
                const cost = e[2];
                if (online[u] && online[v] && cost >= mid) {
                    if (dp[u] + cost < dp[v]) {
                        dp[v] = dp[u] + cost;
                    }
                }
            }
        }
        if (dp[n - 1] <= k) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
